// Validate and prepare HeyGen request
const input = $input.first().json;

// Default avatar and voice settings
const avatarId = input.avatar_id || 'Kristin_pubblic_2_20240108';
const voiceId = input.voice_id || '1bd001e7e50f421d891986aad5158bc8';

// Script/content to speak
const script = input.script || input.text || 'Hello, this is a test video.';

// Overlay configuration (for later processing)
const overlays = input.overlays || [];

// Video dimensions
const width = input.width || 1920;
const height = input.height || 1080;

return {
  json: {
    avatarId,
    voiceId,
    script,
    overlays,
    width,
    height,
    originalRequest: input
  }
};

// Store video ID and overlay config for polling
const response = $input.first().json;
const previousData = $('Prepare HeyGen Request').first().json;

if (response.error) {
  throw new Error(`HeyGen API Error: ${response.error.message || JSON.stringify(response.error)}`);
}

const videoId = response.data?.video_id;

if (!videoId) {
  throw new Error('No video_id returned from HeyGen API');
}

return {
  json: {
    videoId,
    overlays: previousData.overlays,
    pollCount: 0,
    maxPolls: 60,
    status: 'processing'
  }
};

// Check video status and decide next action
const statusResponse = $input.first().json;
const previousData = $('Extract Video ID').first().json;

const status = statusResponse.data?.status;
const videoUrl = statusResponse.data?.video_url;
const pollCount = previousData.pollCount + 1;

return {
  json: {
    videoId: previousData.videoId,
    overlays: previousData.overlays,
    pollCount,
    maxPolls: previousData.maxPolls,
    status,
    videoUrl,
    isComplete: status === 'completed',
    isFailed: status === 'failed',
    shouldContinuePolling: status === 'processing' && pollCount < previousData.maxPolls
  }
};

// Build Cloudinary transformation URL for video overlays
const input = $input.first().json;
const cloudName = $env.CLOUDINARY_CLOUD_NAME;
const videoUrl = input.videoUrl;

// Parse overlays configuration
const overlays = input.overlays || [];

// Build transformation string
let transformations = [];

for (const overlay of overlays) {
  if (overlay.type === 'text') {
    // Text overlay transformation
    const text = encodeURIComponent(overlay.text || 'Sample Text');
    const fontFamily = overlay.fontFamily || 'Arial';
    const fontSize = overlay.fontSize || 48;
    const fontColor = overlay.color || 'white';
    const position = overlay.position || 'south';
    const yOffset = overlay.yOffset || 50;
    const xOffset = overlay.xOffset || 0;

    // Cloudinary text overlay format
    let textOverlay = `l_text:${fontFamily}_${fontSize}:${text}`;
    textOverlay += `,co_rgb:${fontColor.replace('#', '')}`;
    textOverlay += `,g_${position}`;
    if (yOffset) textOverlay += `,y_${yOffset}`;
    if (xOffset) textOverlay += `,x_${xOffset}`;

    // Add timing if specified (start/end in seconds)
    if (overlay.startTime !== undefined || overlay.endTime !== undefined) {
      const start = overlay.startTime || 0;
      const end = overlay.endTime || 'end';
      textOverlay += `,so_${start}`;
      if (end !== 'end') textOverlay += `,eo_${end}`;
    }

    transformations.push(textOverlay);

  } else if (overlay.type === 'image') {
    // Image overlay transformation
    const imagePublicId = overlay.publicId || overlay.imageUrl;
    const width = overlay.width || 200;
    const position = overlay.position || 'north_east';
    const yOffset = overlay.yOffset || 20;
    const xOffset = overlay.xOffset || 20;
    const opacity = overlay.opacity || 100;

    let imageOverlay = `l_${imagePublicId.replace('/', ':')}`;
    imageOverlay += `,w_${width}`;
    imageOverlay += `,o_${opacity}`;
    imageOverlay += `,g_${position}`;
    if (yOffset) imageOverlay += `,y_${yOffset}`;
    if (xOffset) imageOverlay += `,x_${xOffset}`;

    transformations.push(imageOverlay);

  } else if (overlay.type === 'watermark') {
    // Watermark (repeating pattern)
    const imagePublicId = overlay.publicId;
    const opacity = overlay.opacity || 30;

    let watermark = `l_${imagePublicId.replace('/', ':')}`;
    watermark += `,o_${opacity}`;
    watermark += `,fl_tiled`;

    transformations.push(watermark);
  }
}

// Build the final transformation string
const transformationString = transformations.join('/');

return {
  json: {
    videoId: input.videoId,
    originalVideoUrl: videoUrl,
    overlays: input.overlays,
    transformationString,
    cloudName
  }
};

// Extract the transformed video URL
const cloudinaryResponse = $input.first().json;
const previousData = $('Build Cloudinary Transformations').first().json;

// Get the eager transformation result or the main URL
let finalVideoUrl = cloudinaryResponse.secure_url;

if (cloudinaryResponse.eager && cloudinaryResponse.eager.length > 0) {
  finalVideoUrl = cloudinaryResponse.eager[0].secure_url;
}

return {
  json: {
    success: true,
    videoId: previousData.videoId,
    originalVideoUrl: previousData.originalVideoUrl,
    processedVideoUrl: finalVideoUrl,
    cloudinaryPublicId: cloudinaryResponse.public_id,
    duration: cloudinaryResponse.duration,
    format: cloudinaryResponse.format,
    overlaysApplied: previousData.overlays
  }
};

// Return original video without overlays
const input = $input.first().json;

return {
  json: {
    success: true,
    videoId: input.videoId,
    originalVideoUrl: input.videoUrl,
    processedVideoUrl: input.videoUrl,
    overlaysApplied: [],
    message: 'No overlays requested - returning original video'
  }
};

// Return error for failed video generation
const input = $input.first().json;

return {
  json: {
    success: false,
    error: `Video generation failed with status: ${input.status}`,
    videoId: input.videoId,
    pollCount: input.pollCount
  }
};
